#include <stdio.h>
#include <stdlib.h>

int* findPeakGrid(int m, int n, int **mat) {
    int left = 0, right = n - 1;
    int *res = (int*)malloc(2 * sizeof(int));
    while (left <= right) {
        int mid = left + (right - left) / 2;
        int maxRow = 0;
        for (int i = 0; i < m; ++i) {
            if (mat[i][mid] > mat[maxRow][mid]) maxRow = i;
        }
        int leftVal = (mid - 1 >= 0) ? mat[maxRow][mid - 1] : -1;
        int rightVal = (mid + 1 < n) ? mat[maxRow][mid + 1] : -1;
        if (mat[maxRow][mid] > leftVal && mat[maxRow][mid] > rightVal) {
            res[0] = maxRow; res[1] = mid; return res;
        }
        if (leftVal > mat[maxRow][mid]) {
            right = mid - 1;
        } else {
            left = mid + 1;
        }
    }
    res[0] = -1; res[1] = -1; return res; // never reached
}

int main() {
    int m, n; scanf("%d %d", &m, &n);
    int **mat = (int**)malloc(m * sizeof(int*));
    for (int i = 0; i < m; ++i) {
        mat[i] = (int*)malloc(n * sizeof(int));
        for (int j = 0; j < n; ++j) scanf("%d", &mat[i][j]);
    }
    int *ans = findPeakGrid(m, n, mat);
    printf("%d %d\n", ans[0], ans[1]);
    for (int i = 0; i < m; ++i) free(mat[i]);
    free(mat); free(ans);
    return 0;
}

