pair<int,int> findPeakGrid(int m, int n, const vector<vector<int>>& mat) {
    int left = 0, right = n - 1;
    while (left <= right) {
        int mid = left + (right - left) / 2;
        int maxRow = 0;
        for (int i = 0; i < m; ++i) if (mat[i][mid] > mat[maxRow][mid]) maxRow = i;
        int leftVal = (mid - 1 >= 0) ? mat[maxRow][mid - 1] : -1;
        int rightVal = (mid + 1 < n) ? mat[maxRow][mid + 1] : -1;
        if (mat[maxRow][mid] > leftVal && mat[maxRow][mid] > rightVal) return {maxRow, mid};
        if (leftVal > mat[maxRow][mid]) right = mid - 1; else left = mid + 1;
    }
    return {-1,-1}; // never reached
}

