import sys

def findPeakGrid(m, n, mat):
    left, right = 0, n - 1
    while left <= right:
        mid = (left + right) // 2
        max_row = 0
        for i in range(m):
            if mat[i][mid] > mat[max_row][mid]:
                max_row = i
        left_val = mat[max_row][mid - 1] if mid - 1 >= 0 else -1
        right_val = mat[max_row][mid + 1] if mid + 1 < n else -1
        if mat[max_row][mid] > left_val and mat[max_row][mid] > right_val:
            return max_row, mid
        if left_val > mat[max_row][mid]:
            right = mid - 1
        else:
            left = mid + 1
    return -1, -1  # never reached

def main():
    m, n = map(int, sys.stdin.readline().split())
    mat = [list(map(int, sys.stdin.readline().split())) for _ in range(m)]
    i, j = findPeakGrid(m, n, mat)
    print(i, j)

if __name__ == "__main__":
    main()

